    "simulators": {
      "heading": "Disability simulators",
      "description": "Alihkan sebuah simulator ke apply sebuah CSS filter ke halaman behind ini laboratorium. laboratorium itself stays unfiltered so Anda dapat keep menggunakan ini controls. Klik sebuah tile ke aktifkan; klik again ke nonaktifkan. hanya one simulator runs di sebuah waktu.",
      "framing_strong": "Important framing:",
      "framing_body": "simulators adalah imperfect approximations. Mereka adalah useful untuk empathy-building dan cepat checks, tidak untuk verifying compliance. sebuah protanopia filter adalah tidak sama sebagai protanopia. Nyata users memiliki lived dengan mereka condition; Anda adalah seeing itu untuk 60 detik. Gunakan simulators ke surface obvious masalah (warna-hanya informasi, low contrast, illegible teks), kemudian tes dengan nyata users ketika stakes matter.",
      "active_suffix": "· aktif",
      "info_suffix": "· info",
      "blur_amount_label": "Blur amount:",
      "blur_amount_hint": "(2px ≈ mild low vision; 5-8px ≈ severe)",
      "blur_amount_aria": "Blur amount di pixels",
      "stop": "Berhenti simulator",
      "motor_toast": "Motor impairment simulation: lihat info kartu.",
      "tip": "tip: coba warna-blindness simulators di sebuah pelajaran itu menggunakan red/green ke convey meaning (benar/incorrect, peringatan/safe). jika meaning adalah lost di simulation, asli design adalah failing siswa dengan itu condition. Tambah ikon, labels, atau pola alongside warna.",
      "items": {
        "blur_label": "Low-vision blur",
        "blur_desc": "Approximates uncorrected low vision (visual acuity worse than 20/40). Roughly 4% population memiliki uncorrected refractive kesalahan atau lainnya low-vision conditions; ini bagikan adalah much higher among older adults dan siswa dengan visual impairments.",
        "protanopia_label": "Protanopia (red-blind)",
        "protanopia_desc": "Severe red-green warna vision deficiency, missing L-cone. Tentang 1% males dan sangat rare di females. Reds muncul darker; reds dan greens adalah confused.",
        "deuteranopia_label": "Deuteranopia (green-blind)",
        "deuteranopia_desc": "paling umum form warna blindness, missing M-cone. Tentang 6% males. Reds dan greens muncul similar; paling umum form red-green warna vision deficiency.",
        "tritanopia_label": "Tritanopia (blue-blind)",
        "tritanopia_desc": "Rare form, missing S-cone. Tentang 0.01% population. Blues muncul greenish; yellow-blue distinctions adalah lost.",
        "achromatopsia_label": "Achromatopsia (no warna)",
        "achromatopsia_desc": "Selesai absence warna vision. Affects roughly 0.003% population (tentang 1 di 30,000). world muncul di shades grey.",
        "dyslexia_label": "Dyslexia visual stress",
        "dyslexia_desc": "sebuah LIMITED simulation one umum visual-stress experience beberapa dyslexic pembaca laporan (slight blur, lower contrast, shifting spacing). Dyslexia adalah highly individu; ini adalah one slice, tidak sebuah definitive rendering. Tentang 5-10% siswa memiliki dyslexia.",
        "motor_label": "Motor impairments",
        "motor_desc": "Motor impairments resist visual simulation. paling authentic tes adalah ke gunakan OS-tingkat alat nyata siswa gunakan: Windows Sticky Keys, macOS lambat Keys, dwell-klik software, ganti akses (e.g., iOS Ganti Kontrol atau Android Ganti Akses). Coba completing sebuah pelajaran menggunakan hanya one hand, hanya papan ketik, atau hanya one finger."
      }
    }
